import{_ as e,o as i,c as a,ag as t}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"开发者文档","description":"","frontmatter":{},"headers":[{"level":1,"title":"开发者文档","slug":"开发者文档","link":"#开发者文档","children":[{"level":2,"title":"目录简介","slug":"目录简介","link":"#目录简介","children":[]},{"level":2,"title":"项目列表","slug":"项目列表","link":"#项目列表","children":[{"level":3,"title":"CAS 单点登录系统","slug":"cas-单点登录系统","link":"#cas-单点登录系统","children":[]},{"level":3,"title":"智能中间件集成验证脚手架","slug":"智能中间件集成验证脚手架","link":"#智能中间件集成验证脚手架","children":[]}]}]}],"relativePath":"dev/index.md","filePath":"dev/index.md"}'),r={name:"dev/index.md"};function n(o,l,s,d,c,g){return i(),a("div",null,[...l[0]||(l[0]=[t('<h1 id="开发者文档" tabindex="-1">开发者文档 <a class="header-anchor" href="#开发者文档" aria-label="Permalink to &quot;开发者文档&quot;">​</a></h1><h2 id="目录简介" tabindex="-1">目录简介 <a class="header-anchor" href="#目录简介" aria-label="Permalink to &quot;目录简介&quot;">​</a></h2><p>本目录包含北京必码科技工作室提供的开发相关文档和项目，旨在帮助开发者快速上手和使用我们的技术解决方案。</p><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><h3 id="cas-单点登录系统" tabindex="-1">CAS 单点登录系统 <a class="header-anchor" href="#cas-单点登录系统" aria-label="Permalink to &quot;CAS 单点登录系统&quot;">​</a></h3><p>CAS (Central Authentication Service) 是 Apereo 基金会维护的企业级开源单点登录系统，为企业应用提供统一的身份认证与授权机制。我们基于不同版本的 CAS Overlay 进行了定制化开发，提供了完整的开发基座、配置模板和部署方案。</p><p><strong>主要特性：</strong></p><ul><li><strong>架构转型</strong>：从传统 WAR 包架构升级为现代 JAR 包架构，简化部署流程，更好适配微服务环境和容器化部署</li><li><strong>数据库集成</strong>：集成 MyBatis 数据库访问框架，实现与各类关系型数据库的无缝对接</li><li><strong>自定义类启动CAS服务</strong>：提供 <code>CasWebApplication</code> 主启动类，支持开发者进行本地Debug启动和日常开发中的断点调试</li><li><strong>自定义认证验证</strong>：实现灵活的身份验证逻辑，支持自定义用户名密码的登录校验规则</li><li><strong>同时支持OAUTH2.0认证 和 OIDC认证</strong>：并实现自定义的认证返回值格式，支持自定义返回用户信息、角色信息或任意数据</li><li><strong>分布式集群部署</strong>：基于 Redis 支持分布式多节点部署，实现高可用性和扩展性</li><li><strong>安全加固</strong>：关闭 CAS 默认账号密码登录，强制使用自定义认证类，提升系统安全性</li><li><strong>资源提取</strong>：全量提取前端静态资源和模板，方便开发者根据企业品牌定制前端界面</li><li><strong>多语言支持</strong>：内置中文、英文等多语言支持，满足国际化需求（示例）</li><li><strong>容器化部署</strong>：内置DockerFile和Jenkins部署脚本，方便开发者进行容器化部署和持续集成</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./cas-overlay/">CAS Overlay 文档</a> — 包含 7.3.x（JDK 21）、6.6.x（JDK 11）和 5.3.x（JDK 8）系列，各版本均提供 Maven 和 Gradle 两种构建方式</li></ul><h3 id="智能中间件集成验证脚手架" tabindex="-1">智能中间件集成验证脚手架 <a class="header-anchor" href="#智能中间件集成验证脚手架" aria-label="Permalink to &quot;智能中间件集成验证脚手架&quot;">​</a></h3><p>智能中间件集成验证脚手架是面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案，支持开发者快速完成各类常用中间件服务的集成、验证与测试，大幅提升开发效率。</p><p><strong>主要特性：</strong></p><ul><li>AI 接口能力：可调用 Ollama 本地模型和 OpenAI API，支持普通聊天、SSE 流式聊天、文章写作</li><li>多中间件集成：集成了 Elasticsearch、Kafka、MongoDB、MyBatis、RabbitMQ、Redis、RocketMQ 等 7 种常用中间件</li><li>统一 Web 界面：基于 LayUI 2.13.5 框架的直观 Web 界面</li><li>多数据源支持：内置多数据源配置（db1 / db2）</li><li>OAuth2.0 客户端：集成 OAuth2 客户端认证机制，支持登录统一认证中心（CAS）</li><li>多环境配置：支持 dev / qa / prd 多环境配置</li><li>完整测试用例：提供了各中间件的测试用例</li><li>Docker 支持：提供完整的 Docker 部署方案</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./smart-scaffold/">智能中间件集成验证脚手架文档</a> — 包含 Spring Boot 单体版、Dubbo 分布式版和 Spring Cloud 微服务版，均基于 Spring Boot 3.5.12 + Java 17</li></ul>',16)])])}const p=e(r,[["render",n]]);export{u as __pageData,p as default};
